import React, { useState } from 'react';
import { Button, Select, addToast } from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { analyticsService } from '../../../services/analytics/analyticsService';
import { formatVnd, formatDate, formatNumber } from '../../../utils/formatters';
import { exportExcel, MONTH_OPTIONS, YEAR_OPTIONS } from '../../../utils/exportExcel';
import styles from '../../../styles/erpReportPage.module.css';

import type { PayslipRow } from '../../../services/analytics/models';
const BaoCaoLuongPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const now = new Date();
  const [month, setMonth] = useState(now.getMonth() + 1);
  const [year, setYear] = useState(now.getFullYear());
  const [rows, setRows] = useState<PayslipRow[]>([]);
  const [loading, setLoading] = useState(false);
  React.useEffect(() => { let c=false; setLoading(true); const t=setTimeout(()=>{ analyticsService.getPayslips({ month, year }).then(d=>{if(!c)setRows(d);}).catch(e=>{if(!c)dispatch(addToast({message:e?.message??'Lỗi',type:'error'}));}).finally(()=>{if(!c)setLoading(false);}); },0); return ()=>{c=true;clearTimeout(t);}; }, [month,year,dispatch]);
  return (
    <div className={styles.page}>
      <div className={styles.pageHeader}><div className={styles.titleBlock}><h1 className={styles.title}><i className="fas fa-money-check-alt" /> Báo cáo lương</h1><p className={styles.subtitle}>T{month}/{year}</p></div>
        <div className={styles.headerActions}><Select value={String(month)} onChange={e=>setMonth(Number(e.target.value))} options={MONTH_OPTIONS} size="small" /><Select value={String(year)} onChange={e=>setYear(Number(e.target.value))} options={YEAR_OPTIONS} size="small" />
          <Button variant="secondary" onClick={()=>exportExcel('/hr/payslips/export-excel',{month,year},`BaoCaoLuong-T${month}-${year}.xlsx`)}><i className="fas fa-file-excel" /> Xuất Excel</Button></div></div>
      <div className={styles.tableCard}>{loading?<div className={styles.loading}><i className="fas fa-spinner fa-spin" /></div>:rows.length===0?<div className={styles.empty}><p>Không có dữ liệu</p></div>:<div className={styles.tableWrapper}><table className={styles.table}><thead><tr><th>Mã NV</th><th>Họ tên</th><th>PB</th><th className={styles.colRight}>Thu nhập</th><th className={styles.colRight}>Khấu trừ</th><th className={styles.colRight}>Thực lĩnh</th></tr></thead><tbody>{rows.map((r,i)=>(<tr key={r.id??i}><td>{r.employeeCode}</td><td>{r.employeeName}</td><td>{r.departmentName??'—'}</td><td className={styles.colRight}>{formatVnd(r.grossIncome)}</td><td className={styles.colRight}>{formatVnd((r.socialInsuranceEmployee??0)+(r.personalIncomeTax??0))}</td><td className={styles.colRight}>{formatVnd(r.netSalary)}</td></tr>))}</tbody></table></div>}</div>
    </div>
  );
};
export default BaoCaoLuongPage;
